class Solution(object):
    def maxScore(self, grid):
        # Any path score = grid[x2][y2] - grid[x1][y1] (telescoping)
        # Maximize by finding max(grid[x2][y2]) - min(grid[x1][y1]) where x1<=x2, y1<=y2, (x1,y1)!=(x2,y2)
        # For each cell (i,j), find the minimum grid value in the rectangle (0,0)..(i,j) excluding (i,j) itself.
        # min_so_far[i][j] = min of grid[r][c] for r<=i, c<=j
        m, n = len(grid), len(grid[0])
        INF = float('inf')
        # dp_min[i][j] = minimum value in grid[0..i][0..j]
        dp_min = [[INF]*n for _ in range(m)]
        dp_min[0][0] = grid[0][0]
        for j in range(1, n):
            dp_min[0][j] = min(dp_min[0][j-1], grid[0][j])
        for i in range(1, m):
            dp_min[i][0] = min(dp_min[i-1][0], grid[i][0])
        for i in range(1, m):
            for j in range(1, n):
                dp_min[i][j] = min(dp_min[i-1][j], dp_min[i][j-1], grid[i][j])

        ans = -INF
        for i in range(m):
            for j in range(n):
                # Best score ending at (i,j): grid[i][j] - min in [0..i][0..j] excluding self
                # min excluding self: from top or left
                best_min = INF
                if i > 0:
                    best_min = min(best_min, dp_min[i-1][j])
                if j > 0:
                    best_min = min(best_min, dp_min[i][j-1])
                if best_min < INF:
                    ans = max(ans, grid[i][j] - best_min)
        return ans
